import React, { useEffect, useMemo, useState } from 'react';
import { pondService, seasonService } from '../../services/api';
import '../../styles/worker/worker-assigned-ponds.css';
import { pushToast } from "../../utils/toastBridge";
const getPondStatusText = status => {
  const normalized = String(status || '').toUpperCase();
  const map = {
    READY: 'Sẵn sàng',
    RUNNING: 'Đang nuôi',
    MAINTENANCE: 'Bảo trì',
    INACTIVE: 'Tạm dừng'
  };
  return map[normalized] || status || '-';
};
const getPondStatusClass = status => {
  const normalized = String(status || '').toUpperCase();
  if (normalized === 'RUNNING') return 'badge-running';
  if (normalized === 'READY') return 'badge-ready';
  if (normalized === 'MAINTENANCE') return 'badge-maintenance';
  return 'badge-default';
};
const formatArea = value => {
  const number = Number(value);
  if (!Number.isFinite(number)) return '-';
  return new Intl.NumberFormat('vi-VN', {
    maximumFractionDigits: 0
  }).format(number) + ' m2';
};
const formatDepth = value => {
  const number = Number(value);
  if (!Number.isFinite(number)) return '-';
  return number.toFixed(1) + ' m';
};
const formatDate = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '-';
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const WorkerAssignedPonds = () => {
  const [loading, setLoading] = useState(true);
  const [ponds, setPonds] = useState([]);
  const [runningSeasonsByPond, setRunningSeasonsByPond] = useState({});
  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const pondsRes = await pondService.getAllPonds();
        const assignedPonds = pondsRes?.data?.data || [];
        setPonds(assignedPonds);
        const seasonResults = await Promise.all(assignedPonds.map(async pond => {
          try {
            const seasonsRes = await seasonService.getAllSeasons({
              pondId: pond.pond_id
            });
            const seasons = seasonsRes?.data?.data || [];
            const running = seasons.find(season => {
              const status = String(season.status || '').toUpperCase();
              return status === 'RUNNING' || status === 'ACTIVE';
            });
            return [pond.pond_id, running || null];
          } catch (seasonError) {
            return [pond.pond_id, null];
          }
        }));
        setRunningSeasonsByPond(Object.fromEntries(seasonResults));
      } catch (loadError) {
        pushToast({
          title: "Th�t b�i",
          message: loadError?.response?.data?.message || 'Không tải �ược danh sách ao �ược phân công',
          type: "error"
        });
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);
  const stats = useMemo(() => {
    const runningCount = ponds.filter(pond => Boolean(runningSeasonsByPond[pond.pond_id])).length;
    return {
      total: ponds.length,
      running: runningCount,
      idle: ponds.length - runningCount
    };
  }, [ponds, runningSeasonsByPond]);
  return <div className="staff-ponds-page">
      <div className="staff-ponds-header">
        <h1>Ao �ược phân công</h1>
        <p>Danh sách ao bạn �ang phụ trách và mùa vụ �ang chạy tương ứng.</p>
      </div>

      <section className="staff-ponds-summary">
        <article>
          <span>T�"ng ao phụ trách</span>
          <strong>{stats.total}</strong>
        </article>
        <article>
          <span>Ao có mùa vụ chạy</span>
          <strong>{stats.running}</strong>
        </article>
        <article>
          <span>Ao chưa có mùa vụ chạy</span>
          <strong>{stats.idle}</strong>
        </article>
      </section>

      <section className="staff-ponds-list">
        {loading ? <div className="staff-ponds-loading">Đang tải dữ li�!u ao...</div> : ponds.length === 0 ? <div className="staff-ponds-empty">Bạn chưa �ược phân công ao nào.</div> : ponds.map(pond => {
        const runningSeason = runningSeasonsByPond[pond.pond_id];
        return <article className="staff-pond-card" key={pond.pond_id}>
                <header>
                  <div>
                    <p className="pond-code">{pond.pond_code || `AO-${pond.pond_id}`}</p>
                    <h2>{pond.pond_name || 'Ao chưa �ặt tên'}</h2>
                  </div>
                  <span className={`pond-badge ${getPondStatusClass(pond.status)}`}>
                    {getPondStatusText(pond.status)}
                  </span>
                </header>

                <div className="pond-meta-grid">
                  <div>
                    <span>Di�!n tích</span>
                    <strong>{formatArea(pond.area_m2)}</strong>
                  </div>
                  <div>
                    <span>Đ�" sâu</span>
                    <strong>{formatDepth(pond.depth_m)}</strong>
                  </div>
                </div>

                <div className="season-box">
                  <p>Mùa vụ �ang chạy</p>
                  {runningSeason ? <div className="season-content">
                      <strong>{runningSeason.season_name || 'Mùa vụ hi�!n tại'}</strong>
                      <span>Ngày bắt �ầu: {formatDate(runningSeason.start_date)}</span>
                    </div> : <div className="season-empty">Hi�!n chưa có mùa vụ RUNNING cho ao này.</div>}
                </div>
              </article>;
      })}
      </section>
    </div>;
};
export default WorkerAssignedPonds;
